import NavBar from "../components/NavBar";
import Header from "../components/Header";
import Sidebar from "../components/Sidebar";
import WorkChart from "../components/WorkChart";
import BarChart from "../components/BarChart";
import WorkDayChart from "../components/WorkDayChart";
import PayMonthBarChart from "../components/PayMonthBarChart";
import Card from '@mui/material/Card';
import CardActions from '@mui/material/CardActions';
import CardContent from '@mui/material/CardContent';
import CardMedia from '@mui/material/CardMedia';
import Typography from '@mui/material/Typography';
import sales from "../assets/sales.jpg";
import { useNavigate } from "react-router-dom";
import React from "react";
import { PlayCircleOutlined } from '@ant-design/icons';
import { StopOutlined } from '@ant-design/icons';
import Button from "@mui/material/Button";
import IconButton from "@mui/material/IconButton"
import BlockIcon from '@mui/icons-material/Block';
import Grid from '@mui/material/Unstable_Grid2';
import styled from "styled-components";
import axios from "axios";
import { useState } from "react";
import { userState, isWorkingState, workState } from "../recoil/atom";
import { useRecoilState, useRecoilValue } from "recoil";
import { useEffect } from "react";
import Stack from '@mui/material/Stack';

const Sales = styled.img`
        width: 250px;
        height: 170px;
`

const Main = () => {
  const [user, setUser] = useRecoilState(userState);
  const [isWorking, setIsWorking] = useRecoilState(isWorkingState);
  const navigate = useNavigate();

  const validateLocation = (myLat, myLong, latitude, longitude) => {
    const diffLat = Math.abs(myLat - latitude);
    const diffLong = Math.abs(myLong - longitude);
    if (diffLat < 0.05 && diffLong < 0.05) return true;
    return false;
  };

  const getCurrentTime = () => {
    const date = new Date();
    const [hour, minute] = date.toTimeString().split(" ")[0].split(":");
    let [year, month, day] = date.toLocaleString().split(". ");
    if(day.length === 1) day = "0" + day;
    return `${year}-${month}-${day}T${hour}:${minute}`;
  };

  function getNowTime() {
      const date = new Date();
      const [hour, minute] = date.toTimeString().split(" ")[0].split(":");
      let [year, month, day] = date.toLocaleString().split(". ");
      if (day.length === 1) day = "0" + day;
      return `${year}-${month}-${day}`;
    }

  const handleStart = () => {
    const date = new Date();
    const [hour, minute] = date.toTimeString().split(" ")[0].split(":");
    let [year, month, day] = date.toLocaleString().split(". ");
            if(day.length === 1) day = "0" + day;
    console.log("분", minute);
    const startTime = getCurrentTime();

    navigator.geolocation.getCurrentPosition(
      (position) => {
        axios
          .get(`/api/work/start/location/${user.teamId}`)
          .then((response) => {
            const { latitude, longitude } = response.data;
            const isValid = validateLocation(
              position.coords.latitude,
              position.coords.longitude,
              longitude,
              latitude
            );

            if (!isValid) {
              alert("위치에서 벗어났습니다.");
              return;
            }

            axios
              .post(`/api/work/start/${user.id}`, {
                work_start_time: startTime,
              })
              .then((response) => {
                setIsWorking(true);
                alert("근무를 시작합니다.");
              })
              .catch((err) => console.error(err.message));
          });
      },
      (error) => {
        console.error(error);
      },
      {
        enableHighAccuracy: false,
        maximumAge: 0,
        timeout: Infinity,
      }
    );
  };

  const handleEnd = () => {
    axios
      .post(`/api/work/end/${user.id}`, {
        work_end_time: getCurrentTime(),
      })
      .then((response) => {
        setIsWorking(false);
        alert("근무를 종료합니다.");
        window.location.replace("/profile")
      })
      .catch((err) => console.error(err.message));
  };

  useEffect(() => {
      if (!user?.id) {
        const cache = JSON.parse(localStorage.getItem("user"));
        if (!cache) navigate("/login");
        setUser(cache);
      }

  }, []);

  return (
    <>
      <Hello>
      <Header />
      <Sidebar />
      </Hello>
      <InputWrapper>
        <Grid container spacing = {1}>
           <Grid xs = {8}>
                    <CardContent>
                        <Typography gutterBottom variant="h5" component="div">
                            <Start onClick = {handleStart} disabled={isWorking} isWorking={isWorking}>
                            <PlayCircleOutlined /> <br/>
                            근무시작
                            </Start>
                        </Typography>
                    </CardContent>
            </Grid>
            <Grid xs = {4}>
                    <CardContent>
                        <Typography gutterBottom  variant="h5" component="div">
                            <End onClick = {handleEnd}>
                            <StopOutlined /> <br/>
                            근무종료
                            </End>
                        </Typography>
                    </CardContent>
            </Grid>
        </Grid>
        </InputWrapper>
        <div>
            <br/>
            <br/>
            <br/>
        </div>
        <Grid container rowSpacing = {4} columnSpacing={{ xs:1, sm:2, md:3}}>
            <Grid xs = {6}>
                <GraphWrapper>
                <h2> 일별 일한 시간 </h2>
                            <WorkChart />
                </GraphWrapper>
            </Grid>
            <Grid xs = {6}>
                <Graph2Wrapper>
                <h2> 월별 일한 시간 </h2>
                            <BarChart />
                </Graph2Wrapper>
            </Grid>
            <Grid xs = {6}>
                <Graph3Wrapper>
                <h2> 요일별 일한 시간 </h2>
                            <WorkDayChart />
                </Graph3Wrapper>
            </Grid>
            <Grid xs = {6}>
                <Graph4Wrapper>
                <h2> 월별 월급 </h2>
                        <PayMonthBarChart />
                </Graph4Wrapper>
            </Grid>
        </Grid>
    </>
  );
};
export default Main;

const Start = styled.button`

    margin-left : 100px;
    width: 350px;
    height: 200px;
    color : black;
    border : #a673ff;
    background : lightblue;
    border-radius: 30px;
    cursor : pointer;

    &:hover:before{
        content : "";
        position: absolute;
        top : 0;
        left : 23%;
        width : 28%;
        height : 95%;
        background: rgba(0,0,0,.1);
        border-radius: 30px;
    }

    font-size : 3.0rem;
    font-family: 'watermelonsalad';
    font-weight : bold;

    ${props =>
        props.isWorking &&
        `
          background: blue;
          font-color: white;
        `};
`;


const End = styled.button`

    width: 350px;
    height: 200px;
    color : black;
    border : #a673ff;
    background : pink;
    border-radius: 30px;
    cursor : pointer;

    &:hover:before {
            content : "";
            position: absolute;
            top : 0;
            left : 69.5%;
            width : 28%;
            height : 95%;
            background: rgba(0,0,0,.1);
            border-radius: 30px;
        }

    font-size : 3.0rem;
    font-family: 'watermelonsalad';
    font-weight : bold;
`;

const InputWrapper = styled.div`
  position : absolute;
  text-align: center;
  margin-top : 150px;
  margin-left : 300px;
  background : white;
  width : 1300px;
`;

const GraphWrapper = styled.div`
  position : relative;
  margin-top : 370px;
  margin-left : 350px;
  font-family : "watermelonsalad";
`;

const Graph2Wrapper = styled.div`
  position : absolute;
  margin-top : 370px;
  margin-left : 0px;
  font-family : "watermelonsalad";
`;


const Graph3Wrapper = styled.div`
  position : relative;
  margin-top : 0px;
  margin-left : 390px;
  font-family : "watermelonsalad";
`;

const Graph4Wrapper = styled.div`
  position : absolute;
  margin-top : 0px;
  margin-left : 0px;
  font-family : "watermelonsalad";
`;

const Hello = styled.div`
  position : absolute;
`;

const test = styled.div`
  font-family : "watermelonsald";
`;
